outSequence.script:
var body = mc.getPayloadJSON();
				if(body.Disciplinas.Disciplina == undefined) {
					mc.setProperty('notFound',true);
					body = {};
				}
				else {
					body = body.Disciplinas.Disciplina[0];
					body["_type"] = 'Disciplina';
					if(body.PreRequisitos.Disciplina != undefined) {
						body.preRequisito = body.PreRequisitos.Disciplina;
						for(i = 0; i < body.preRequisito.length; i++) {
							body.preRequisito[i]["_type"] = 'Disciplina';
						}
					}
					delete body.PreRequisitos;
					mc.setProperty('notFound',false);
				}
				mc.setPayloadJSON(body);
